// El frontend envía: { nombre, telefono, franja, resumen, bloques, foto_antes, origen, fecha }
// bloques es el array genérico {tipo, ...datos} del contrato multi-cliente
// (puntuaciones, fortalezas, recomendaciones, checklist, propuesta,
// horquilla_precio, imagen_despues) — distinto según qué cliente lo envíe.
//
// Este nodo aplana a texto legible los bloques de DATOS (todo menos
// imagen_despues), y convierte a adjuntos de email reales las dos fotos:
// - foto_antes: la foto original que subió el cliente (siempre que exista).
// - foto_despues: la simulación generada por la IA, si el bloque
//   {tipo:"imagen_despues", url} viene con una imagen en base64.
// Antes esto se imprimía como texto plano (un muro de base64 ilegible);
// ahora se adjunta como imagen de verdad.

const body = $input.first().json.body || $input.first().json;

function formatearBloque(b) {
  switch (b.tipo) {
    case 'puntuaciones':
      return 'Puntuación por zonas:\n' + (b.items || [])
        .map((i) => `  - ${i.nombre}: ${i.puntuacion}/100 — ${i.observacion}`)
        .join('\n');
    case 'fortalezas':
      return 'Fortalezas:\n' + (b.items || []).map((i) => `  - ${i}`).join('\n');
    case 'recomendaciones':
      return 'Recomendaciones:\n' + (b.items || [])
        .map((r) => `  - ${r.titulo} (${r.zona}): ${r.beneficio}${r.detalle ? '. ' + r.detalle : ''}`)
        .join('\n');
    case 'checklist':
      return 'Checklist:\n' + (b.items || [])
        .map((c) => `  - [${c.estado}] ${c.nombre}${c.observacion ? ': ' + c.observacion : ''}`)
        .join('\n');
    case 'propuesta':
      return 'Propuesta:\n' + (b.partidas || [])
        .map((p) => `  - ${p.nombre}: ${p.descripcion}`)
        .join('\n');
    case 'horquilla_precio': {
      const rango = `${b.minimo}–${b.maximo} ${b.moneda || ''}`.trim();
      return `Rango de precio orientativo: ${rango}${b.nota ? ' (' + b.nota + ')' : ''}`;
    }
    // imagen_despues NO se formatea aquí como texto: se adjunta como foto (ver más abajo)
    default:
      return null;
  }
}

const bloques = Array.isArray(body.bloques) ? body.bloques : [];
let bloques_texto = bloques
  .filter((b) => b.tipo !== 'imagen_despues')
  .map(formatearBloque)
  .filter(Boolean)
  .join('\n\n') || '(sin bloques en el informe)';

const binary = {};
const adjuntos = [];

// Foto "antes": la foto original del cliente
if (body.foto_antes) {
  const buffer = Buffer.from(body.foto_antes, 'base64');
  binary.foto_antes = await this.helpers.prepareBinaryData(buffer, 'antes.jpg', 'image/jpeg');
  adjuntos.push('foto original ("antes")');
}

// Foto "después": bloque {tipo:"imagen_despues", url} — url puede venir como
// data URI completa (data:image/png;base64,...) o como base64 "pelado".
// Si en el futuro llega como URL http(s) real, no se descarga aquí (haría
// falta un nodo HTTP Request previo): se deja como enlace en el texto.
const bloqueDespues = bloques.find((b) => b.tipo === 'imagen_despues' && b.url);
if (bloqueDespues) {
  const raw = bloqueDespues.url;
  const match = typeof raw === 'string' && raw.match(/^data:(image\/\w+);base64,(.*)$/);
  if (match) {
    binary.foto_despues = await this.helpers.prepareBinaryData(Buffer.from(match[2], 'base64'), 'despues.jpg', match[1]);
    adjuntos.push('simulación de la IA ("después")');
  } else if (typeof raw === 'string' && /^https?:\/\//.test(raw)) {
    bloques_texto += `\n\nImagen "después" alojada externamente (no se adjunta automáticamente): ${raw}`;
  } else if (typeof raw === 'string' && raw.length > 100) {
    binary.foto_despues = await this.helpers.prepareBinaryData(Buffer.from(raw, 'base64'), 'despues.jpg', 'image/jpeg');
    adjuntos.push('simulación de la IA ("después")');
  }
}

const notaAdjuntos = adjuntos.length
  ? `\n\nSe adjunta: ${adjuntos.join(' y ')}.`
  : '';

return [{
  json: {
    nombre: body.nombre || '',
    telefono: body.telefono || '',
    franja: body.franja || '',
    resumen: body.resumen || '',
    origen: body.origen || '',
    fecha: body.fecha || '',
    bloques_texto: bloques_texto + notaAdjuntos,
  },
  binary,
}];

